          label: 'Angle      (0–180°)',
          type: 'number',
          min: 0,
          max: 180,
          placeholder: 'Angle'
        }, {
          id: 'press_time',
          label: 'Press Time (0–300s)',
          type: 'number',
          min: 0,
          max: 300,
          placeholder: 'Press time'
        }],
        'CRB': []
      }
    }, {
      type: 'buttons',
      items: [{
        label: 'Open Lid',
        cls: 'btn-success',
        action: 'isp_lid_open'
      }, {
        label: 'Close Lid',
        cls: 'btn-danger',
        action: 'isp_lid_close'
      }]
    }]
  }]
},
// ══════════════════════════════════════════════════════════════════════════
// MODULE 0+1 – COMBINATIONAL
// ══════════════════════════════════════════════════════════════════════════
{
  id: 'combo',
  name: 'Combo',
  icon: 'Server',
  color: '#e67e22',
  sub: 'Combined power & display ops',
  features: [
  // ── 24. Power ON with Delay ──────────────────────────────────────────
  // PWRON_WITH_DELAY:<TIME>;   TIME 0-1000   → POWERED_ON_WITH_DELAY;
  {
    id: 'combo_pwron_delay',
    title: 'Power ON with Delay',
    desc: 'Power on SUT after a configurable delay of 0–1000 seconds.',
    controls: [{
      type: 'dynamic',
      id: 'pwron_params',
      // → dp('pwron_params', 'delay_time')
      label: 'Delay',
      fields: {
        'default': [{
          id: 'delay_time',
          label: 'Delay (0–1000 s)',
          type: 'number',
          min: 0,
          max: 1000,
          placeholder: 'Seconds'
        }]
      }
    }, {
      type: 'buttons',
      items: [{
        label: 'Execute',
        cls: 'btn-warning',
        action: 'pwron_delay'
      }]
    }]
  },
  // ── 25. Close Lid → Wait → Open Lid ─────────────────────────────────
  // CLOSE_LID_WAIT_OPEN_LID:<TIME>;   TIME 0-1000 → CLOSED_LID_WAITED_OPENED_LID;
  {
    id: 'combo_lid_wait',
    title: 'Close Lid → Wait → Open Lid',
    desc: 'Close lid, wait for the specified time, then open the lid.',
    controls: [{
      type: 'dynamic',
      id: 'lid_wait_params',
      // → dp('lid_wait_params', 'wait_time')
      label: 'Wait Time',
      fields: {
        'default': [{
          id: 'wait_time',
          label: 'Wait Time (0–1000 s)',
          type: 'number',
          min: 0,
          max: 1000,
          placeholder: 'Seconds'
        }]
      }
    }, {
      type: 'buttons',
      items: [{
        label: 'Execute',
        cls: 'btn-warning',
        action: 'close_lid_wait_open'
      }]
    }]
  },
  // ── 26. Lid & Power Sequences ────────────────────────────────────────
  // CLOSE_LID_PWRON_SUT;                              → CLOSED_LID_PWRDON_SUT;
  // CLOSE_N_OPEN_LID_PWRON_SUT;                       → CLOSED_N_OPENED_LID_PWRDON_SUT;
  // CLOSE_LID_HOTPLUG_ALL_DPS_N_OPEN_LID_PWRDON_SUT; → CLOSED_LID_HOTPLUGED_ALL_DPS_N_OPENED_LID_PWRON_SUT;
  {
    id: 'combo_lid_ops',
    title: 'Lid & Power Sequences',
    desc: 'Combined lid and power-on sequences for SUT bring-up.',
    controls: [{
      type: 'buttons',
      items: [{
        label: 'Close Lid → PWR ON SUT',
        cls: 'btn-primary',
        action: 'close_lid_pwron'
      }, {
        label: 'Close → Open Lid → PWR ON SUT',
        cls: 'btn-primary',
        action: 'close_n_open_lid_pwron'
      }, {
        label: 'Close Lid + Hotplug DPs → Open → PWR ON',
        cls: 'btn-warning',
        action: 'close_lid_hotplug_dps'
      }]
    }]
  },
  // ── 27. All Ports Hotplug / Unplug ──────────────────────────────────
  // HOTPLUG_ALL_PORTS;   → HOTPLUGED_ALL_PORTS;
  // UNPLUG_ALL_PORTS;    → UNPLUGED_ALL_PORTS;
  {
    id: 'combo_all_ports',
    title: 'All Ports Hotplug / Unplug',
    desc: 'Hotplug or unplug all display and peripheral ports simultaneously.',
    controls: [{
      type: 'buttons',
      items: [{
        label: 'Hotplug All Ports',
        cls: 'btn-success',
        action: 'hotplug_all_ports'
      }, {
        label: 'Unplug All Ports',
        cls: 'btn-danger',
        action: 'unplug_all_ports'
      }]
    }]
  }]
}];

