// ─────────────────────────────────────────────────────────────────────────────
// modulesData.js  –  AMD Hardware Test Dashboard
//
// Command format  :  [COMMAND]:[ARG1],[ARG2];
// Response format :  [STATUS]:[VALUE];
//
// action keys here map 1-to-1 with cases in useCommand.js → buildCommand()
// dynamic control ids & field ids must match the dp() calls in useCommand.js
// ─────────────────────────────────────────────────────────────────────────────

export const MODULES = [

  // ══════════════════════════════════════════════════════════════════════════
  // MODULE 1 – POWER
  // ══════════════════════════════════════════════════════════════════════════
  {
    id: 'power',
    name: 'Power',
    icon: 'Power',
    color: '#f39c12',
    sub: 'Power control & status',
    features: [

      // ── 1. Power ON / OFF ────────────────────────────────────────────────
      {
        id: 'power_onoff',
        title: 'Power ON / OFF',
        desc: 'Power ON or OFF for Laptop OEM, Desktop, or CRB. Select target and fill parameters.',
        controls: [
          {
            type: 'select',
            id: 'power_target',           // → p.power_target in buildCommand
            label: 'Target',
            options: ['Laptop OEM', 'Desktop', 'CRB']
          },
          {
            type: 'dynamic',
            id: 'power_params',           // → dp('power_params', ...) in buildCommand
            label: 'Parameters',
            fields: {
              // PWR_ON/OFF_LT:<ANGLE>,<TIME>;   ANGLE 0-180, TIME 0-60
              'Laptop OEM': [
                { id: 'angle', label: 'Angle (0–180°)', type: 'number', min: 0, max: 180, placeholder: 'Angle' },
                { id: 'time',  label: 'Time  (0–60 s)', type: 'number', min: 0, max: 60,  placeholder: 'Time'  }
              ],
              // PWR_ON/OFF_DT:<TIME>;   TIME 0-5
              'Desktop': [
                { id: 'time', label: 'Time (0–5 s)', type: 'number', min: 0, max: 5, placeholder: 'Time' }
              ],
              // PWR_ON/OFF_CRB:<TIME>;   TIME 0-5
              'CRB': [
                { id: 'time', label: 'Time (0–5 s)', type: 'number', min: 0, max: 5, placeholder: 'Time' }
              ]
            }
          },
          {
            type: 'buttons',
            items: [
              { label: 'Power ON',  cls: 'btn-success', action: 'pwr_on'  },
              { label: 'Power OFF', cls: 'btn-danger',  action: 'pwr_off' }
            ]
          }
        ]
      },

      // ── 2. Power Restart ─────────────────────────────────────────────────
      {
        id: 'power_restart',
        title: 'Power Restart',
        desc: 'Restart Laptop OEM (angle + timings), Desktop, or CRB (pulse time).',
        controls: [
          {
            type: 'select',
            id: 'rst_target',             // → p.rst_target
            label: 'Target',
            options: ['Laptop OEM', 'Desktop', 'CRB']
          },
          {
            type: 'dynamic',
            id: 'rst_params',             // → dp('rst_params', ...)
            label: 'Parameters',
            fields: {
              // PWR_RST_LT:<ANGLE>,<TIME_ON>,<WAITTIME>,<TIME_OFF>;   all 0-60
              'Laptop OEM': [
                { id: 'angle',     label: 'Angle  (0–180°)',   type: 'number', min: 0, max: 180, placeholder: 'Angle'    },
                { id: 'time_on',   label: 'Time ON   (0–60s)', type: 'number', min: 0, max: 60,  placeholder: 'ON time'  },
                { id: 'wait_time', label: 'Wait      (0–60s)', type: 'number', min: 0, max: 60,  placeholder: 'Wait'     },
                { id: 'time_off',  label: 'Time OFF  (0–60s)', type: 'number', min: 0, max: 60,  placeholder: 'OFF time' }
              ],
              // PWR_RST_DT:<PULSE_TIME>;   0-60
              'Desktop': [
                { id: 'pulse_time', label: 'Pulse Time (0–60s)', type: 'number', min: 0, max: 60, placeholder: 'Pulse' }
              ],
              // PWR_RST_CRB:<PULSE_TIME>;   0-60
              'CRB': [
                { id: 'pulse_time', label: 'Pulse Time (0–60s)', type: 'number', min: 0, max: 60, placeholder: 'Pulse' }
              ]
            }
          },
          {
            type: 'buttons',
            items: [
              { label: 'Restart', cls: 'btn-warning', action: 'pwr_rst' }
            ]
          }
        ]
      },

      // ── 3. Power Status ──────────────────────────────────────────────────
      // Response: LAPTOP POWERED: <ON/OFF>, <VOLTAGE>;
      //           DESKTOP POWERED: <ON/OFF>, <VOLTAGE>;
      //           CRB POWERED: <ON/OFF>, <VOLTAGE>;
      {
        id: 'power_status',
        title: 'Power Status',
        desc: 'Read power state and voltage for Laptop, Desktop, or CRB.',
        controls: [
          {
            type: 'select',
            id: 'pstat_target',           // → p.pstat_target
            label: 'Target',
            options: ['Laptop', 'Desktop', 'CRB']
          },
          {
            type: 'buttons',
            items: [
              { label: 'Read Status', cls: 'btn-primary', action: 'pwr_status' }
            ]
          }
        ]
      },

      // ── 4. AC Power ──────────────────────────────────────────────────────
      // PWR_ON_AC;  PWR_OFF_AC;  PWR_STATUS_AC;
      // Response: AC ON;  AC OFF;  AC:<ON/OFF>, <VOLTAGE>;
      {
        id: 'ac_power',
        title: 'AC Power Control',
        desc: 'Control and read AC power supply status.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: 'AC ON',     cls: 'btn-success', action: 'pwr_on_ac'     },
              { label: 'AC OFF',    cls: 'btn-danger',  action: 'pwr_off_ac'    },
              { label: 'AC Status', cls: 'btn-primary', action: 'pwr_status_ac' }
            ]
          }
        ]
      },

      // ── 5. Module Status ─────────────────────────────────────────────────
      // MODULE_STATUS:<ModuleNumber>;   Response: ONLINE / OFFLINE
      {
        id: 'module_status',
        title: 'Module Status Check',
        desc: 'Check ONLINE / OFFLINE status of hardware modules 1–4.',
        controls: [
          {
            type: 'dynamic',
            id: 'mod_params',             // → dp('mod_params', 'module_num')
            label: 'Module',
            fields: {
              'default': [
                { id: 'module_num', label: 'Module No. (1–4)', type: 'number', min: 1, max: 4, placeholder: '1–4' }
              ]
            }
          },
          {
            type: 'buttons',
            items: [
              { label: 'Check Status', cls: 'btn-primary', action: 'module_status' }
            ]
          }
        ]
      }
    ]
  },

  // ══════════════════════════════════════════════════════════════════════════
  // MODULE 2 – DISPLAY
  // ══════════════════════════════════════════════════════════════════════════
  {
    id: 'display',
    name: 'Display',
    icon: 'Monitor',
    color: '#4f8cff',
    sub: 'Display & lid control',
    features: [

      // ── 6. Display Port Hotplug / Unplug / Status ────────────────────────
      // HOTPLUG_DP_1;  HOTPLUG_DP_2;  HOTPLUG_HDMI_1;  HOTPLUG_HDMI_2;
      // HOTPLUG_USB4_1;  HOTPLUG_USB4_2;
      // UNPLUG_DP_1;  etc.
      // PLUG_STATUS_DP_1;  PLUG_STATUS_USB_1;  (note: USB not USB4 for status)
      {
        id: 'disp_ports',
        title: 'Display Port Hotplug / Unplug',
        desc: 'Hotplug, unplug, or read plug status for DP, HDMI, and USB4 ports.',
        controls: [
          {
            type: 'select',
            id: 'disp_port',              // → p.disp_port
            label: 'Port',
            options: ['DP_1', 'DP_2', 'HDMI_1', 'HDMI_2', 'USB4_1', 'USB4_2']
          },
          {
            type: 'buttons',
            items: [
              { label: 'Hotplug',     cls: 'btn-success',   action: 'disp_hotplug'     },
              { label: 'Unplug',      cls: 'btn-danger',    action: 'disp_unplug'      },
              { label: 'Plug Status', cls: 'btn-primary',   action: 'disp_plug_status' }
            ]
          }
        ]
      },

      // ── 7. Lid Open / Close (Display module) ────────────────────────────
      // LID_OPEN_LT:<ANGLE>;            ANGLE 0-180   → LID_OPENED;
      // LID_CLOSE_LT:<ANGLE>,<TIME>;    TIME  0-300   → LID_CLOSED;
      // LID_OPEN_CRB;  LID_CLOSE_CRB;               → LID_OPENED; / LID_CLOSED;
      {
        id: 'lid_ctrl',
        title: 'Lid Open / Close',
        desc: 'Control lid servo for Laptop OEM (angle + press-time) or CRB (no params).',
        controls: [
          {
            type: 'select',
            id: 'lid_target',             // → p.lid_target
            label: 'Target',
            options: ['Laptop OEM', 'CRB']
          },
          {
            type: 'dynamic',
            id: 'lid_params',             // → dp('lid_params', ...)
            label: 'Parameters',
            fields: {
              'Laptop OEM': [
                { id: 'angle',      label: 'Angle      (0–180°)', type: 'number', min: 0, max: 180, placeholder: 'Angle'      },
                { id: 'press_time', label: 'Press Time (0–300s)', type: 'number', min: 0, max: 300, placeholder: 'Press time' }
              ],
              'CRB': []   // LID_OPEN_CRB / LID_CLOSE_CRB need no params
            }
          },
          {
            type: 'buttons',
            items: [
              { label: 'Open Lid',  cls: 'btn-success', action: 'lid_open'  },
              { label: 'Close Lid', cls: 'btn-danger',  action: 'lid_close' }
            ]
          }
        ]
      },

      // ── 8. Display Properties ────────────────────────────────────────────
      // READ_DISP_PROP;
      // Response: R:<val>, G:<val>, B:<val>, C:<val>, LUX:<val>, CT:<val>, INT:<val>;
      {
        id: 'disp_prop',
        title: 'Display Properties',
        desc: 'Read RGB, Color Temperature, Luminance, and sensor data from the display.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: 'Read Display Properties', cls: 'btn-primary', action: 'read_disp_prop' }
            ]
          }
        ]
      }
    ]
  },

  // ══════════════════════════════════════════════════════════════════════════
  // MODULE 4 – AUDIO
  // ══════════════════════════════════════════════════════════════════════════
  {
    id: 'audio',
    name: 'Audio',
    icon: 'Volume2',
    color: '#9b59b6',
    sub: 'Audio hotplug & Bluetooth',
    features: [

      // ── 9. Audio Hotplug ─────────────────────────────────────────────────
      // HOTPLUG_3_5_MM;  HOTPLUG_USB_A;  HOTPLUG_USB_C;  HOTPLUG_HDMI;
      {
        id: 'audio_hotplug',
        title: 'Audio Hotplug',
        desc: 'Simulate audio device connection for 3.5 mm jack, USB-A, USB-C, and HDMI.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: '3.5 mm Plug', cls: 'btn-success', action: 'hotplug_3_5_mm'    },
              { label: 'USB-A Plug',  cls: 'btn-success', action: 'hotplug_usb_a'      },
              { label: 'USB-C Plug',  cls: 'btn-success', action: 'hotplug_usb_c'      },
              { label: 'HDMI Plug',   cls: 'btn-success', action: 'hotplug_hdmi_audio' }
            ]
          }
        ]
      },

      // ── 10. Audio Unplug ─────────────────────────────────────────────────
      // UNPLUG_3_5_MM;  UNPLUG_USB_A;  UNPLUG_USB_C;  UNPLUG_HDMI;
      {
        id: 'audio_unplug',
        title: 'Audio Unplug',
        desc: 'Simulate audio device disconnection for 3.5 mm jack, USB-A, USB-C, and HDMI.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: '3.5 mm Unplug', cls: 'btn-danger', action: 'unplug_3_5_mm'    },
              { label: 'USB-A Unplug',  cls: 'btn-danger', action: 'unplug_usb_a'      },
              { label: 'USB-C Unplug',  cls: 'btn-danger', action: 'unplug_usb_c'      },
              { label: 'HDMI Unplug',   cls: 'btn-danger', action: 'unplug_hdmi_audio' }
            ]
          }
        ]
      },

      // ── 11. Bluetooth Power ──────────────────────────────────────────────
      // TURN_ON_BT;  → BT_TURNED_ON
      // TURN_OFF_BT; → BT_TURNED_OFF;
      {
        id: 'bt_power',
        title: 'Bluetooth Power',
        desc: 'Turn the Bluetooth module on or off.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: 'BT ON',  cls: 'btn-success', action: 'bt_on'  },
              { label: 'BT OFF', cls: 'btn-danger',  action: 'bt_off' }
            ]
          }
        ]
      },

      // ── 12. Bluetooth Name Change ────────────────────────────────────────
      // CHANGE_BT_NAME:<NEW_NAME>;   → BT_NAME_CHANGED;
      // Separated into its own card so the text-input validation doesn't block
      // the other BT action buttons.
      {
        id: 'bt_name',
        title: 'Bluetooth Name Change',
        desc: 'Change the Bluetooth device name to any valid BT name.',
        controls: [
          {
            type: 'dynamic',
            id: 'bt_name_params',         // → dp('bt_name_params', 'name')
            label: 'BT Name',
            fields: {
              'default': [
                { id: 'name', label: 'New BT Name', type: 'text', placeholder: 'e.g. PARADISE' }
              ]
            }
          },
          {
            type: 'buttons',
            items: [
              { label: 'Change Name', cls: 'btn-warning', action: 'bt_change_name' }
            ]
          }
        ]
      },

      // ── 13. Bluetooth Pairing & Connection ───────────────────────────────
      // EN_BT_PARING_MODE;   → BT_PARING_EN;
      // BT_CONNECTION_STATUS;→ <ON/OFF/CONNECTED/PAIRING_MODE>
      // BT_CONNECT;          → BT_CONNECTED;
      // BT_DISCONNECT;       → BT_DISCONNECTED;
      {
        id: 'bt_pairing',
        title: 'Bluetooth Pairing & Connection',
        desc: 'Enable pairing mode, check status, connect, or disconnect Bluetooth.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: 'Pair Mode',  cls: 'btn-primary',   action: 'bt_pair_mode'  },
              { label: 'BT Status',  cls: 'btn-secondary', action: 'bt_status'     },
              { label: 'Connect',    cls: 'btn-success',   action: 'bt_connect'    },
              { label: 'Disconnect', cls: 'btn-danger',    action: 'bt_disconnect' }
            ]
          }
        ]
      },

      // ── 14. BT Audio Playback ────────────────────────────────────────────
      // BT_PLAY;  BT_PAUSE;  BT_NEXT;  BT_PREVIOUS;
      {
        id: 'bt_playback',
        title: 'BT Audio Playback',
        desc: 'Control Bluetooth audio playback: play, pause, next, previous.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: '▶  Play',   cls: 'btn-success',   action: 'bt_play'     },
              { label: '⏸  Pause',  cls: 'btn-warning',   action: 'bt_pause'    },
              { label: '⏭  Next',   cls: 'btn-primary',   action: 'bt_next'     },
              { label: '⏮  Prev',   cls: 'btn-secondary', action: 'bt_previous' }
            ]
          }
        ]
      },

      // ── 15. BT Audio Volume ──────────────────────────────────────────────
      // BT_AUDIO_UP;  BT_AUDIO_DOWN;  BT_AUDIO_MUTE;  BT_AUDIO_UNMUTE;
      // (Controls the 3.5 mm audio jack volume)
      {
        id: 'bt_volume',
        title: 'BT Audio Volume',
        desc: 'Adjust Bluetooth / 3.5 mm audio volume and toggle mute.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: 'Vol +',    cls: 'btn-success',   action: 'bt_audio_up'     },
              { label: 'Vol −',    cls: 'btn-danger',    action: 'bt_audio_down'   },
              { label: 'Mute',     cls: 'btn-warning',   action: 'bt_audio_mute'   },
              { label: 'Unmute',   cls: 'btn-primary',   action: 'bt_audio_unmute' }
            ]
          }
        ]
      },

      // ── 16. BT Audio Logs ───────────────────────────────────────────────
      // BT_AUDIO_GET_LOGS;   → AUDIO_GET_BT; (sends audio configuration)
      {
        id: 'bt_logs',
        title: 'BT Audio Logs',
        desc: 'Retrieve Bluetooth audio configuration and log data.',
        controls: [
          {
            type: 'buttons',
            items: [
              { label: 'Get Audio Logs', cls: 'btn-primary', action: 'bt_get_logs' }
            ]
          }
        ]
      }
    ]
  },

  // ══════════════════════════════════════════════════════════════════════════
  // MODULE 3 – ISP / CAMERA
  // ══════════════════════════════════════════════════════════════════════════
  {
    id: 'isp',
    name: 'ISP',
    icon: 'Camera',
    color: '#1abc9c',
    sub: 'Camera, RGB & light control',
    features: [

      // ── 17. RGB LED Set ──────────────────────────────────────────────────
      // RGB_SET:<LED_ID>,<R>,<G>,<B>;
      // LED_ID: 1→RGB LED 1, 2→RGB LED 2   R,G,B: 0-255
      // Response: RGB LED <LED_ID> SET : R:<val>, G:<val>, B:<val>;
      {
        id: 'rgb_set',
        title: 'RGB LED Set',
        desc: 'Set RGB LED color. Select LED (1 or 2) and enter R, G, B values (0–255).',
        controls: [
          {
            type: 'select',
            id: 'rgb_led_id',             // → p.rgb_led_id
            label: 'LED ID',
            options: ['1', '2']
          },
          {
            type: 'dynamic',
            id: 'rgb_params',             // → dp('rgb_params', 'r'/'g'/'b')
            label: 'RGB Values',
            fields: {
              '1': [
                { id: 'r', label: 'R (0–255)', type: 'number', min: 0, max: 255, placeholder: 'Red'   },
                { id: 'g', label: 'G (0–255)', type: 'number', min: 0, max: 255, placeholder: 'Green' },
                { id: 'b', label: 'B (0–255)', type: 'number', min: 0, max: 255, placeholder: 'Blue'  }
              ],
              '2': [
                { id: 'r', label: 'R (0–255)', type: 'number', min: 0, max: 255, placeholder: 'Red'   },
                { id: 'g', label: 'G (0–255)', type: 'number', min: 0, max: 255, placeholder: 'Green' },
                { id: 'b', label: 'B (0–255)', type: 'number', min: 0, max: 255, placeholder: 'Blue'  }
              ]
            }
          },
          {
            type: 'buttons',
            items: [
              { label: 'Set RGB', cls: 'btn-success', action: 'rgb_set' }
            ]
          }
        ]
      },

      // ── 18. RGB LED Off ──────────────────────────────────────────────────
      // RGB_OFF:<LED_ID>;   Response: RGB LED <LED_ID> OFF;
      // Kept separate from RGB Set so "Off" button doesn't trigger R/G/B validation
      {
        id: 'rgb_off',
        title: 'RGB LED Off',
        desc: 'Turn off RGB LED 1 or LED 2.',
        controls: [
          {
            type: 'select',
            id: 'rgb_led_id',             // → p.rgb_led_id
            label: 'LED ID',
            options: ['1', '2']
          },
          {
            type: 'buttons',
            items: [
